before_code:
library ieee;
use ieee.std_logic_1164.all;

entity priority_decoder is
  port (
    input_bus : in std_logic_vector(63 downto 0);
    priority_level : in std_logic_vector(2 downto 0);
    output_data : out std_logic_vector(63 downto 0)
  );
end entity;

architecture rtl of priority_decoder is
begin
  process(input_bus) is
  begin
    case priority_level is
      when "000" => output_data <= input_bus;
      when "001" => output_data <= input_bus(62 downto 0) & '0';
      when "010" => output_data <= input_bus(61 downto 0) & "00";
      when others => output_data <= (others => '0');
    end case;
  end process;
end architecture;

